 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    using namespace sqlgen::literals;

    // Connect to the database
    auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
    if (!conn_result) {
        throw std::runtime_error("Failed to connect to database");
    }
    auto conn = conn_result.value();

    // Build the base query
    auto query = sqlgen::read<std::vector<Book>>;

    // Create conditions based on provided filters
    auto conditions = std::vector<decltype(auto)>{};

    if (filters.title_keyword) {
        conditions.emplace_back("title"_c.like("%" + *filters.title_keyword + "%"));
    }

    if (filters.min_year) {
        conditions.emplace_back("year"_c >= *filters.min_year);
    }

    if (filters.genre) {
        conditions.emplace_back("genre"_c == *filters.genre);
    }

    if (filters.max_price) {
        conditions.emplace_back("price"_c <= *filters.max_price);
    }

    // Combine conditions with logical AND
    if (!conditions.empty()) {
        auto combined_condition = conditions[0];
        for (size_t i = 1; i < conditions.size(); ++i) {
            combined_condition = combined_condition && conditions[i];
        }

        query = query | sqlgen::where(combined_condition);
    }

    // Execute the query and return results
    auto result = query(conn);
    if (!result) {
        throw std::runtime_error("Query execution failed");
