```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <rfl.hpp>
#include <algorithm>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

bool migration_add_column() {
  // 1. Connect to the SQLite database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // 2. Check if User table exists
  auto table_exists = conn.table_exists("User");
  if (!table_exists) {
    return false; // Table doesn't exist, migration cannot proceed
  }

  // 3. Get current and target table structures
  auto current_table = sqlgen::transpilation::to_create_table<User>();
  auto target_table = sqlgen::transpilation::to_create_table<UserAfter>();

  // 4. Compare column structures to find missing columns
  std::vector<std::string> current_columns;
  for (const auto& col : current_table.columns) {
    current_columns.push_back(col.name);
  }

  std::vector<std::string> target_columns;
  for (const auto& col : target_table.columns) {
    target_columns.push_back(col.name);
  }

  // Find columns that exist in target but not in current
  std::vector<std::string> missing_columns;
  std::set_difference(
      target_columns.begin(), target_columns.end(),
      current_columns.begin(), current_columns.end(),
      std::back_inserter(missing_columns)
  );

  // 5. Generate and execute ALTER TABLE statements
  for (const auto& col_name : missing_columns) {
    if (col_name == "phone_number") {
      // Add phone_number column (VARCHAR)
      auto result = conn.execute(
          "ALTER TABLE User ADD COLUMN phone_number VARCHAR(20)"
      );
      if (!result) {
        return false;
      }
    } else if (col_name == "is_active") {
      // Add is_active column (BOOLEAN as INTEGER with default)
      auto result = conn.execute(
          "ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1"
      );
      if (!result) {
        return false;
      }
    }
  }

  return true;
}

} // namespace schema_migration_add_column
```

## Key Implementation Details:

1. **Database Connection**: Uses `sqlgen::sqlite::connect()` to establish connection to "test_db.sqlite"

2. **Table Existence Check**: Uses `conn.table_exists("User")` to verify the User table exists before proceeding

3. **Table Structure Comparison**: 
   - Uses `sqlgen::transpilation::to_create_table<T>()` to get both current and target table structures
   - Compares column names using set difference algorithm to identify missing columns

4. **Dynamic ALTER TABLE Generation**:
   - Executes appropriate SQL statements based on the missing columns identified
   - Uses SQLite-specific syntax for VARCHAR and INTEGER with DEFAULT values
   - Properly handles BOOLEAN as INTEGER with DEFAULT 1 in SQLite

5. **Error Handling**: Returns false immediately if any operation fails, ensuring atomicity of the migration

The implementation follows the sqlgen principles by leveraging the library's type-safe table structure introspection while handling the SQLite-specific SQL generation for schema modifications.

