#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Begin transaction
  auto begin_result = sqlgen::begin_transaction(conn);
  if (!begin_result) {
    return false;
  }

  // Read from account to check balance
  auto from_account_result = (sqlgen::read<Account> | sqlgen::where("account_id"_c == from_account_id))(conn);
  if (!from_account_result) {
    sqlgen::rollback(conn);
    return false;
  }
  auto from_account = *from_account_result;

  // Check if sufficient funds exist
  if (from_account.balance < amount) {
    sqlgen::rollback(conn);
    return false;
  }

  // Update from account: deduct amount
  auto update_from_result = (sqlgen::update<Account>("balance"_c.set(from_account.balance - amount))
                          | sqlgen::where("account_id"_c == from_account_id && "balance"_c == from_account.balance))(conn);
  if (!update_from_result) {
    sqlgen::rollback(conn);
    return false;
  }

  // Update to account: add amount
  auto to_account_result = (sqlgen::read<Account> | sqlgen::where("account_id"_c == to_account_id))(conn);
  if (!to_account_result) {
    sqlgen::rollback(conn);
    return false;
  }
  auto to_account = *to_account_result;

  auto update_to_result = (sqlgen::update<Account>("balance"_c.set(to_account.balance + amount))
                          | sqlgen::where("account_id"_c == to_account_id))(conn);
  if (!update_to_result) {
    sqlgen::rollback(conn);
    return false;
  }

  // Commit transaction
  auto commit_result = sqlgen::commit(conn);
  if (!commit_result) {
    sqlgen::rollback(conn);
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
```

