  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
