    if (!res.department_name.has_value()) null_dept_count++;
    if (!res.first_name.has_value()) null_emp_count++;
  }
  EXPECT_EQ(null_dept_count, 1); // Alice
  EXPECT_EQ(null_emp_count, 1); // Marketing
